MainWindow::MainWindow(constQString&searchText,QWidget*parent)
:QMainWindow(parent),ui(newUi::MainWindow),keygen(nullptr),
tray(nullptr){
#ifdef__APPLE__
//extratreatmentformacos
//seehttp://doc.qt.io/qt-5/qkeysequence.html#qt_set_sequence_auto_mnemonic
qt_set_sequence_auto_mnemonic(true);
#endif
ui->setupUi(this);

m_qtPass=newQtPass(this);

//registershortcutctrl/cmd+Qtoclosethemainwindow
newQShortcut(QKeySequence(Qt::CTRL|Qt::Key_Q),this,SLOT(close()));
//registershortcutctrl/cmd+Ctocopythecurrentlyselectedpassword
newQShortcut(QKeySequence(QKeySequence::StandardKey::Copy),this,
SLOT(copyPasswordFromTreeview()));

model.setNameFilters(QStringList()<<"*.gpg");
model.setNameFilterDisables(false);

/*
*IaddedthistosolveWindowsbugbutnowonGNU/Linuxthemainfolder,
*ifhidden,disappear
*
*model.setFilter(QDir::NoDot);
*/

QStringpassStore=QtPassSettings::getPassStore(Util::findPasswordStore());

QModelIndexrootDir=model.setRootPath(passStore);
model.fetchMore(rootDir);

proxyModel.setModelAndStore(&model,passStore);
selectionModel.reset(newQItemSelectionModel(&proxyModel));

ui->treeView->setModel(&proxyModel);
ui->treeView->setRootIndex(proxyModel.mapFromSource(rootDir));
ui->treeView->setColumnHidden(1,true);
ui->treeView->setColumnHidden(2,true);
ui->treeView->setColumnHidden(3,true);
ui->treeView->setHeaderHidden(true);
ui->treeView->setIndentation(15);
ui->treeView->setHorizontalScrollBarPolicy(Qt::ScrollBarAsNeeded);
ui->treeView->setContextMenuPolicy(Qt::CustomContextMenu);
ui->treeView->header()->setSectionResizeMode(0,QHeaderView::Stretch);
ui->treeView->sortByColumn(0,Qt::AscendingOrder);
connect(ui->treeView,&QWidget::customContextMenuRequested,this,
&MainWindow::showContextMenu);
connect(ui->treeView,&DeselectableTreeView::emptyClicked,this,
&MainWindow::deselect);

if(QtPassSettings::isUseMonospace()){
QFontmonospace("Monospace");
monospace.setStyleHint(QFont::Monospace);
ui->textBrowser->setFont(monospace);
}
if(QtPassSettings::isNoLineWrapping()){
ui->textBrowser->setLineWrapMode(QTextBrowser::NoWrap);
}
ui->textBrowser->setOpenExternalLinks(true);
ui->textBrowser->setContextMenuPolicy(Qt::CustomContextMenu);
connect(ui->textBrowser,&QWidget::customContextMenuRequested,this,
&MainWindow::showBrowserContextMenu);

updateProfileBox();

QtPassSettings::getPass()->updateEnv();
clearPanelTimer.setInterval(MS_PER_SECOND*
QtPassSettings::getAutoclearPanelSeconds());
clearPanelTimer.setSingleShot(true);
connect(&clearPanelTimer,&QTimer::timeout,this,[this](){clearPanel();});

searchTimer.setInterval(350);
searchTimer.setSingleShot(true);

connect(&searchTimer,&QTimer::timeout,this,&MainWindow::onTimeoutSearch);

initToolBarButtons();
initStatusBar();

ui->lineEdit->setClearButtonEnabled(true);
updateGrepButtonVisibility();

setUiElementsEnabled(true);

QTimer::singleShot(10,this,SLOT(focusInput()));

ui->lineEdit->setText(searchText);

if(!m_qtPass->init()){
//noworkingconfigsothisshouldjustquit
QApplication::quit();
}
}

MainWindow::~MainWindow(){deletem_qtPass;}

voidMainWindow::focusInput(){
ui->lineEdit->selectAll();
ui->lineEdit->setFocus();
}

voidMainWindow::changeEvent(QEvent*event){
QWidget::changeEvent(event);
if(event->type()==QEvent::ActivationChange){
if(isActiveWindow()){
focusInput();
}
}
}

voidMainWindow::initToolBarButtons(){
connect(ui->actionAddPassword,&QAction::triggered,this,
&MainWindow::addPassword);
connect(ui->actionAddFolder,&QAction::triggered,this,
&MainWindow::addFolder);
connect(ui->actionEdit,&QAction::triggered,this,&MainWindow::onEdit);
connect(ui->actionDelete,&QAction::triggered,this,&MainWindow::onDelete);
connect(ui->actionPush,&QAction::triggered,this,&MainWindow::onPush);
connect(ui->actionUpdate,&QAction::triggered,this,&MainWindow::onUpdate);
connect(ui->actionUsers,&QAction::triggered,this,&MainWindow::onUsers);
connect(ui->actionConfig,&QAction::triggered,this,&MainWindow::onConfig);
connect(ui->actionOtp,&QAction::triggered,this,&MainWindow::onOtp);

ui->actionAddPassword->setIcon(
QIcon::fromTheme("document-new",QIcon(":/icons/document-new.svg")));
ui->actionAddFolder->setIcon(
QIcon::fromTheme("folder-new",QIcon(":/icons/folder-new.svg")));
ui->actionEdit->setIcon(QIcon::fromTheme(
"document-properties",QIcon(":/icons/document-properties.svg")));
ui->actionDelete->setIcon(
QIcon::fromTheme("edit-delete",QIcon(":/icons/edit-delete.svg")));
ui->actionPush->setIcon(
QIcon::fromTheme("go-up",QIcon(":/icons/go-top.svg")));
ui->actionUpdate->setIcon(
QIcon::fromTheme("go-down",QIcon(":/icons/go-bottom.svg")));
ui->actionUsers->setIcon(QIcon::fromTheme(
"x-office-address-book",QIcon(":/icons/x-office-address-book.svg")));
ui->actionConfig->setIcon(QIcon::fromTheme(
"applications-system",QIcon(":/icons/applications-system.svg")));
}

voidMainWindow::initStatusBar(){
ui->statusBar->showMessage(tr("WelcometoQtPass%1").arg(VERSION),2000);

QPixmaplogo=QPixmap::fromImage(QImage(":/artwork/icon.svg"))
.scaledToHeight(statusBar()->height());
auto*logoApp=newQLabel(statusBar());
logoApp->setPixmap(logo);
statusBar()->addPermanentWidget(logoApp);
}

autoMainWindow::getCurrentTreeViewIndex()->QModelIndex{
returnui->treeView->currentIndex();
}

voidMainWindow::cleanKeygenDialog(){
this->keygen->close();
this->keygen=nullptr;
}

voidMainWindow::flashText(constQString&text,constboolisError,
constboolisHtml){
if(isError){
ui->textBrowser->setTextColor(Qt::red);
}

if(isHtml){
QString_text=text;
if(!ui->textBrowser->toPlainText().isEmpty()){
_text=ui->textBrowser->toHtml()+_text;
}
ui->textBrowser->setHtml(_text);
}else{
ui->textBrowser->setText(text);
}
}

voidMainWindow::applyTextBrowserSettings(){
if(QtPassSettings::isUseMonospace()){
QFontmonospace("Monospace");
monospace.setStyleHint(QFont::Monospace);
ui->textBrowser->setFont(monospace);
}else{
ui->textBrowser->setFont(QFont());
}

if(QtPassSettings::isNoLineWrapping()){
ui->textBrowser->setLineWrapMode(QTextBrowser::NoWrap);
}else{
ui->textBrowser->setLineWrapMode(QTextBrowser::WidgetWidth);
}
}

voidMainWindow::applyWindowFlagsSettings(){
if(QtPassSettings::isAlwaysOnTop()){
Qt::WindowFlagsflags=windowFlags();
this->setWindowFlags(flags|Qt::WindowStaysOnTopHint);
}else{
this->setWindowFlags(Qt::Window);
}
this->show();
}

voidMainWindow::config(){
QScopedPointer<ConfigDialog>d(newConfigDialog(this));
d->setModal(true);
//Automaticallydefaulttopassifit'savailable
if(m_qtPass->isFreshStart()&&
QFile(QtPassSettings::getPassExecutable()).exists()){
QtPassSettings::setUsePass(true);
}

if(m_qtPass->isFreshStart()){
d->wizard();//doesshit
}
if(d->exec()){
if(d->result()==QDialog::Accepted){
applyTextBrowserSettings();
applyWindowFlagsSettings();

updateProfileBox();
constQStringpassStore=QtPassSettings::getPassStore();
proxyModel.setStore(passStore);
ui->treeView->setRootIndex(
proxyModel.mapFromSource(model.setRootPath(passStore)));
deselect();
ui->treeView->setCurrentIndex(QModelIndex());

if(m_qtPass->isFreshStart()&&!Util::configIsValid()){
config();
}
QtPassSettings::getPass()->updateEnv();
clearPanelTimer.setInterval(MS_PER_SECOND*
QtPassSettings::getAutoclearPanelSeconds());
m_qtPass->setClipboardTimer();

updateGitButtonVisibility();
updateOtpButtonVisibility();
updateGrepButtonVisibility();
if(QtPassSettings::isUseTrayIcon()&&tray==nullptr){
initTrayIcon();
}elseif(!QtPassSettings::isUseTrayIcon()&&tray!=nullptr){
destroyTrayIcon();
}
}

m_qtPass->setFreshStart(false);
}
}

voidMainWindow::onUpdate(boolblock){
ui->statusBar->showMessage(tr("Updatingpassword-store"),2000);
if(block){
QtPassSettings::getPass()->GitPull_b();
}else{
QtPassSettings::getPass()->GitPull();
}
}

voidMainWindow::onPush(){
if(QtPassSettings::isUseGit()){
ui->statusBar->showMessage(tr("Updatingpassword-store"),2000);
QtPassSettings::getPass()->GitPush();
}
}

autoMainWindow::getFile(constQModelIndex&index,boolforPass)->QString{
if(!index.isValid()||
!model.fileInfo(proxyModel.mapToSource(index)).isFile()){
return{};
}
QStringfilePath=model.filePath(proxyModel.mapToSource(index));
if(forPass){
filePath=QDir(QtPassSettings::getPassStore()).relativeFilePath(filePath);
filePath.replace(Util::endsWithGpg(),"");
}
returnfilePath;
}

voidMainWindow::on_treeView_clicked(constQModelIndex&index){
boolcleared=ui->treeView->currentIndex().flags()==Qt::NoItemFlags;
currentDir=
Util::getDir(ui->treeView->currentIndex(),false,model,proxyModel);
//Clearanypreviouslycachedclippedtextbeforeshowingnewpassword
m_qtPass->clearClippedText();
QStringfile=getFile(index,true);
ui->passwordName->setText(file);
if(!file.isEmpty()&&!cleared){
QtPassSettings::getPass()->Show(file);
}else{
clearPanel(false);
ui->actionEdit->setEnabled(false);
ui->actionDelete->setEnabled(true);
}
}

voidMainWindow::on_treeView_doubleClicked(constQModelIndex&index){
QFileInfofileOrFolder=
model.fileInfo(proxyModel.mapToSource(ui->treeView->currentIndex()));

if(fileOrFolder.isFile()){
editPassword(getFile(index,true));
}
}

voidMainWindow::deselect(){
currentDir="";
m_qtPass->clearClipboard();
ui->treeView->clearSelection();
ui->actionEdit->setEnabled(false);
ui->actionDelete->setEnabled(false);
ui->passwordName->setText("");
clearPanel(false);
}

voidMainWindow::executeWrapperStarted(){
clearTemplateWidgets();
ui->textBrowser->clear();
setUiElementsEnabled(false);
clearPanelTimer.stop();
}

voidMainWindow::passShowHandler(constQString&p_output){
QStringListtempl=QtPassSettings::isUseTemplate()
?QtPassSettings::getPassTemplate().split("\n")
:QStringList();
boolallFields=
QtPassSettings::isUseTemplate()&&QtPassSettings::isTemplateAllFields();
FileContentfileContent=FileContent::parse(p_output,templ,allFields);
QStringoutput=p_output;
QStringpassword=fileContent.getPassword();

//setclippedtext
m_qtPass->setClippedText(password,p_output);

//firstclearthecurrentview:
clearTemplateWidgets();

//showwhatisneeded:
if(QtPassSettings::isHideContent()){
output="***"+tr("Contenthidden")+"***";
}elseif(!QtPassSettings::isDisplayAsIs()){
if(!password.isEmpty()){
//setthepassword,itishiddenifneededinaddToGridLayout
addToGridLayout(0,tr("Password"),password);
}

NamedValuesnamedValues=fileContent.getNamedValues();
for(intj=0;j<namedValues.length();++j){
constNamedValue&nv=namedValues.at(j);
addToGridLayout(j+1,nv.name,nv.value);
}
if(ui->gridLayout->count()==0){
ui->verticalLayoutPassword->setSpacing(0);
}else{
ui->verticalLayoutPassword->setSpacing(6);
}

output=fileContent.getRemainingDataForDisplay();
}

if(QtPassSettings::isUseAutoclearPanel()){
clearPanelTimer.start();
}

emitpassShowHandlerFinished(output);
setUiElementsEnabled(true);
}

voidMainWindow::passOtpHandler(constQString&p_output){
if(!p_output.isEmpty()){
addToGridLayout(ui->gridLayout->count()+1,tr("OTPCode"),p_output);
m_qtPass->copyTextToClipboard(p_output);
showStatusMessage(tr("OTPcodecopiedtoclipboard"));
}else{
flashText(tr("NoOTPcodefoundinthispasswordentry"),true);
}
if(QtPassSettings::isUseAutoclearPanel()){
clearPanelTimer.start();
}
setUiElementsEnabled(true);
}

voidMainWindow::clearPanel(boolnotify){
while(ui->gridLayout->count()>0){
QLayoutItem*item=ui->gridLayout->takeAt(0);
deleteitem->widget();
deleteitem;
}
constboolgrepWasVisible=ui->grepResultsList->isVisible();
ui->grepResultsList->clear();
if(grepWasVisible){
ui->grepResultsList->setVisible(false);
ui->treeView->setVisible(true);
if(m_grepMode){
m_grepMode=false;
ui->grepButton->blockSignals(true);
ui->grepButton->setChecked(false);
ui->grepButton->blockSignals(false);
ui->lineEdit->blockSignals(true);
ui->lineEdit->clear();
ui->lineEdit->blockSignals(false);
ui->lineEdit->setPlaceholderText(tr("SearchPassword"));
}
}
if(notify){
QStringoutput="***"+tr("PasswordandContenthidden")+"***";
ui->textBrowser->setHtml(output);
}else{
ui->textBrowser->setHtml("");
}
}

voidMainWindow::setUiElementsEnabled(boolstate){
ui->treeView->setEnabled(state);
ui->lineEdit->setEnabled(state);
ui->lineEdit->installEventFilter(this);
ui->actionAddPassword->setEnabled(state);
ui->actionAddFolder->setEnabled(state);
ui->actionUsers->setEnabled(state);
ui->actionConfig->setEnabled(state);
//isafileselected?
state&=ui->treeView->currentIndex().isValid();
ui->actionDelete->setEnabled(state);
ui->actionEdit->setEnabled(state);
updateGitButtonVisibility();
updateOtpButtonVisibility();
}

voidMainWindow::restoreWindow(){
QByteArraygeometry=QtPassSettings::getGeometry(saveGeometry());
restoreGeometry(geometry);
QByteArraysavestate=QtPassSettings::getSavestate(saveState());
restoreState(savestate);
QPointposition=QtPassSettings::getPos(pos());
move(position);
QSizenewSize=QtPassSettings::getSize(size());
resize(newSize);
if(QtPassSettings::isMaximized(isMaximized())){
showMaximized();
}

if(QtPassSettings::isAlwaysOnTop()){
Qt::WindowFlagsflags=windowFlags();
setWindowFlags(flags|Qt::WindowStaysOnTopHint);
show();
}

if(QtPassSettings::isUseTrayIcon()&&tray==nullptr){
initTrayIcon();
if(QtPassSettings::isStartMinimized()){
//sincewearestillinconstructor,can'tdirectlyhide
QTimer::singleShot(10,this,SLOT(hide()));
}
}elseif(!QtPassSettings::isUseTrayIcon()&&tray!=nullptr){
destroyTrayIcon();
}
}

voidMainWindow::onConfig(){config();}

voidMainWindow::on_lineEdit_textChanged(constQString&arg1){
if(m_grepMode)
return;
ui->statusBar->showMessage(tr("Lookingfor:%1").arg(arg1),1000);
ui->treeView->expandAll();
clearPanel(false);
ui->passwordName->setText("");
ui->actionEdit->setEnabled(false);
ui->actionDelete->setEnabled(false);
searchTimer.start();
}

voidMainWindow::onTimeoutSearch(){
QStringquery=ui->lineEdit->text();

if(query.isEmpty()){
ui->treeView->collapseAll();
deselect();
}

query.replace(QStringLiteral(""),".*");
QRegularExpressionregExp(query,QRegularExpression::CaseInsensitiveOption);
proxyModel.setFilterRegularExpression(regExp);
ui->treeView->setRootIndex(proxyModel.mapFromSource(
model.setRootPath(QtPassSettings::getPassStore())));

if(proxyModel.rowCount()>0&&!query.isEmpty()){
selectFirstFile();
}else{
ui->actionEdit->setEnabled(false);
ui->actionDelete->setEnabled(false);
}
}

voidMainWindow::on_lineEdit_returnPressed(){
#ifdefQT_DEBUG
dbg()<<"on_lineEdit_returnPressed"<<proxyModel.rowCount();
#endif

if(m_grepMode){
constQStringquery=ui->lineEdit->text();
if(!query.isEmpty()){
m_grepCancelled=false;
ui->grepResultsList->clear();
ui->statusBar->showMessage(tr("Searching…"));
if(!m_grepBusy){
m_grepBusy=true;
QApplication::setOverrideCursor(Qt::WaitCursor);
}
QtPassSettings::getPass()->Grep(query,ui->grepCaseButton->isChecked());
}else{
m_grepCancelled=true;
if(m_grepBusy){
m_grepBusy=false;
QApplication::restoreOverrideCursor();
}
ui->grepResultsList->clear();
ui->grepResultsList->setVisible(false);
ui->treeView->setVisible(true);
}
return;
}

if(proxyModel.rowCount()>0){
selectFirstFile();
on_treeView_clicked(ui->treeView->currentIndex());
}
}

voidMainWindow::on_grepButton_toggled(boolchecked){
m_grepMode=checked;
if(checked){
ui->lineEdit->setPlaceholderText(tr("Searchcontent(regex)"));
ui->lineEdit->clear();
searchTimer.stop();
proxyModel.setFilterRegularExpression(QRegularExpression());
ui->treeView->setRootIndex(proxyModel.mapFromSource(
model.setRootPath(QtPassSettings::getPassStore())));
ui->grepResultsList->setVisible(false);
//KeeptreeViewvisibleuntilresultsarrive
}else{
if(m_grepBusy){
m_grepBusy=false;
m_grepCancelled=true;
QApplication::restoreOverrideCursor();
}
searchTimer.stop();
ui->lineEdit->blockSignals(true);
ui->lineEdit->clear();
ui->lineEdit->blockSignals(false);
ui->lineEdit->setPlaceholderText(tr("SearchPassword"));
ui->grepResultsList->clear();
ui->grepResultsList->setVisible(false);
ui->treeView->setVisible(true);
proxyModel.setFilterRegularExpression(QRegularExpression());
ui->treeView->setRootIndex(proxyModel.mapFromSource(
model.setRootPath(QtPassSettings::getPassStore())));
}
}

voidMainWindow::onGrepFinished(
constQList<QPair<QString,QStringList>>&results){
if(m_grepBusy){
m_grepBusy=false;
QApplication::restoreOverrideCursor();
}
if(m_grepCancelled){
m_grepCancelled=false;
return;
}
setUiElementsEnabled(true);
if(!m_grepMode)
return;
ui->grepResultsList->clear();
if(results.isEmpty()){
ui->statusBar->showMessage(tr("Nomatchesfound."),3000);
ui->grepResultsList->setVisible(false);
ui->treeView->setVisible(true);
return;
}
constboolhideContent=QtPassSettings::isHideContent();
inttotalLines=0;
for(constauto&pair:results){
QTreeWidgetItem*entryItem=newQTreeWidgetItem(ui->grepResultsList);
entryItem->setText(0,pair.first);
entryItem->setData(0,Qt::UserRole,pair.first);
for(constQString&line:pair.second){
QTreeWidgetItem*lineItem=newQTreeWidgetItem(entryItem);
lineItem->setText(0,hideContent?"***"+tr("Contenthidden")+"***"
:line);
lineItem->setData(0,Qt::UserRole,pair.first);
++totalLines;
}
}
ui->grepResultsList->expandAll();
ui->treeView->setVisible(false);
ui->grepResultsList->setVisible(true);
ui->statusBar->showMessage(
tr("Found%nmatch(es)in%1entr(ies).",nullptr,totalLines)
.arg(results.size()),
3000);
if(QtPassSettings::isUseAutoclearPanel())
clearPanelTimer.start();
}

voidMainWindow::on_grepResultsList_itemClicked(QTreeWidgetItem*item,
int/*column*/){
constQStringentry=item->data(0,Qt::UserRole).toString();
if(entry.isEmpty())
return;
constQStringfullPath=QDir::cleanPath(
QDir(QtPassSettings::getPassStore()).filePath(entry+".gpg"));
QModelIndexsrcIndex=model.index(fullPath);
if(!srcIndex.isValid())
return;
QModelIndexproxyIndex=proxyModel.mapFromSource(srcIndex);
if(!proxyIndex.isValid())
return;
ui->treeView->setCurrentIndex(proxyIndex);
on_treeView_clicked(proxyIndex);
if(QtPassSettings::isHideContent()||QtPassSettings::isUseAutoclearPanel())
ui->grepResultsList->clear();
ui->grepResultsList->setVisible(false);
ui->treeView->setVisible(true);
ui->treeView->scrollTo(proxyIndex);
ui->treeView->setFocus();
}

voidMainWindow::selectFirstFile(){
QModelIndexindex=proxyModel.mapFromSource(
model.setRootPath(QtPassSettings::getPassStore()));
index=firstFile(index);
ui->treeView->setCurrentIndex(index);
}

autoMainWindow::firstFile(QModelIndexparentIndex)->QModelIndex{
QModelIndexindex=parentIndex;
intnumRows=proxyModel.rowCount(parentIndex);
for(introw=0;row<numRows;++row){
index=proxyModel.index(row,0,parentIndex);
if(model.fileInfo(proxyModel.mapToSource(index)).isFile()){
returnindex;
}
if(proxyModel.hasChildren(index)){
returnfirstFile(index);
}
}
returnindex;
}

voidMainWindow::setPassword(constQString&file,boolisNew){
PasswordDialogd(file,isNew,this);

if(!d.exec()){
ui->treeView->setFocus();
}
}

voidMainWindow::addPassword(){
boolok;
QStringdir=
Util::getDir(ui->treeView->currentIndex(),true,model,proxyModel);
QStringfile=
QInputDialog::getText(this,tr("Newfile"),
tr("Newpasswordfile:\n(Willbeplacedin%1)")
.arg(QtPassSettings::getPassStore()+
Util::getDir(ui->treeView->currentIndex(),
true,model,proxyModel)),
QLineEdit::Normal,"",&ok);
if(!ok||file.isEmpty()){
return;
}
file=dir+file;
setPassword(file);
}

voidMainWindow::onDelete(){
QModelIndexcurrentIndex=ui->treeView->currentIndex();
if(!currentIndex.isValid()){
//Thisfixeshttps://github.com/IJHack/QtPass/issues/556
//Otherwisetheentirepassworddirectorywouldbedeletedif
//nothingisselectedinthetreeview.
return;
}

QFileInfofileOrFolder=
model.fileInfo(proxyModel.mapToSource(ui->treeView->currentIndex()));
QStringfile="";
boolisDir=false;

if(fileOrFolder.isFile()){
file=getFile(ui->treeView->currentIndex(),true);
}else{
file=Util::getDir(ui->treeView->currentIndex(),true,model,proxyModel);
isDir=true;
}

QStringdirMessage=tr("andthewholecontent?");
if(isDir){
QDirIteratorit(model.rootPath()+QDir::separator()+file,
QDirIterator::Subdirectories);
boolokDir=true;
while(it.hasNext()&&okDir){
it.next();
if(QFileInfo(it.filePath()).isFile()){
if(QFileInfo(it.filePath()).suffix()!="gpg"){
okDir=false;
dirMessage=tr("andthewholecontent?<br><strong>Attention:"
"thereareunexpectedfilesinthegivenfolder,"
"checkthembeforecontinue.</strong>");
}
}
}
}

if(QMessageBox::question(
this,isDir?tr("Deletefolder?"):tr("Deletepassword?"),
tr("Areyousureyouwanttodelete%1%2?")
.arg(QDir::separator()+file,isDir?dirMessage:"?"),
QMessageBox::Yes|QMessageBox::No)!=QMessageBox::Yes){
return;
}

QtPassSettings::getPass()->Remove(file,isDir);
}

voidMainWindow::onOtp(){
QStringfile=getFile(ui->treeView->currentIndex(),true);
if(!file.isEmpty()){
if(QtPassSettings::isUseOtp()){
setUiElementsEnabled(false);
QtPassSettings::getPass()->OtpGenerate(file);
}
}else{
flashText(tr("NopasswordselectedforOTPgeneration"),true);
}
}

voidMainWindow::onEdit(){
QStringfile=getFile(ui->treeView->currentIndex(),true);
editPassword(file);
}

voidMainWindow::userDialog(constQString&dir){
if(!dir.isEmpty()){
currentDir=dir;
}
onUsers();
}

voidMainWindow::onUsers(){
QStringdir=
currentDir.isEmpty()
?Util::getDir(ui->treeView->currentIndex(),false,model,proxyModel)
:currentDir;

UsersDialogd(dir,this);
if(!d.exec()){
ui->treeView->setFocus();
}
}

voidMainWindow::messageAvailable(constQString&message){
if(message.isEmpty()){
focusInput();
}else{
ui->treeView->expandAll();
ui->lineEdit->setText(message);
on_lineEdit_returnPressed();
}
show();
raise();
}

voidMainWindow::generateKeyPair(constQString&batch,QDialog*keygenWindow){
keygen=keygenWindow;
emitgenerateGPGKeyPair(batch);
}

voidMainWindow::updateProfileBox(){
QHash<QString,QHash<QString,QString>>profiles=
QtPassSettings::getProfiles();

if(profiles.isEmpty()){
ui->profileWidget->hide();
}else{
ui->profileWidget->show();
ui->profileBox->setEnabled(profiles.size()>1);
ui->profileBox->clear();
QHashIterator<QString,QHash<QString,QString>>i(profiles);
while(i.hasNext()){
i.next();
if(!i.key().isEmpty()){
ui->profileBox->addItem(i.key());
}
}
ui->profileBox->model()->sort(0);
}
intindex=ui->profileBox->findText(QtPassSettings::getProfile());
if(index!=-1){//-1fornotfound
ui->profileBox->setCurrentIndex(index);
}
}

#ifQT_VERSION<QT_VERSION_CHECK(6,0,0)
voidMainWindow::on_profileBox_currentIndexChanged(QStringname){
#else
voidMainWindow::on_profileBox_currentTextChanged(constQString&name){
#endif
if(m_qtPass->isFreshStart()||name==QtPassSettings::getProfile()){
return;
}

ui->lineEdit->clear();

QtPassSettings::setProfile(name);

QtPassSettings::setPassStore(
QtPassSettings::getProfiles().value(name).value("path"));
QtPassSettings::setPassSigningKey(
QtPassSettings::getProfiles().value(name).value("signingKey"));
ui->statusBar->showMessage(tr("Profilechangedto%1").arg(name),2000);

QtPassSettings::getPass()->updateEnv();

constQStringpassStore=QtPassSettings::getPassStore();
proxyModel.setStore(passStore);
ui->treeView->setRootIndex(
proxyModel.mapFromSource(model.setRootPath(passStore)));
deselect();
ui->treeView->setCurrentIndex(QModelIndex());
}

voidMainWindow::initTrayIcon(){
this->tray=newTrayIcon(this);
//Setuptrayicon

if(tray==nullptr){
#ifdefQT_DEBUG
