voidMainWindow::closeEvent(QCloseEvent*event){
if(QtPassSettings::isHideOnClose()){
this->hide();
event->ignore();
}else{
m_qtPass->clearClipboard();

QtPassSettings::setGeometry(saveGeometry());
QtPassSettings::setSavestate(saveState());
QtPassSettings::setMaximized(isMaximized());
if(!isMaximized()){
QtPassSettings::setPos(pos());
QtPassSettings::setSize(size());
}
event->accept();
}
}

autoMainWindow::eventFilter(QObject*obj,QEvent*event)->bool{
if(obj==ui->lineEdit&&event->type()==QEvent::KeyPress){
auto*key=dynamic_cast<QKeyEvent*>(event);
if(key!=nullptr&&key->key()==Qt::Key_Down){
ui->treeView->setFocus();
}
}
returnQObject::eventFilter(obj,event);
}

voidMainWindow::keyPressEvent(QKeyEvent*event){
switch(event->key()){
caseQt::Key_Delete:
onDelete();
break;
caseQt::Key_Return:
caseQt::Key_Enter:
if(proxyModel.rowCount()>0){
on_treeView_clicked(ui->treeView->currentIndex());
}
break;
caseQt::Key_Escape:
ui->lineEdit->clear();
break;
default:
break;
}
}

voidMainWindow::showContextMenu(constQPoint&pos){
QModelIndexindex=ui->treeView->indexAt(pos);
boolselected=true;
if(!index.isValid()){
ui->treeView->clearSelection();
ui->actionDelete->setEnabled(false);
ui->actionEdit->setEnabled(false);
currentDir="";
selected=false;
}

ui->treeView->setCurrentIndex(index);

QPointglobalPos=ui->treeView->viewport()->mapToGlobal(pos);

QFileInfofileOrFolder=
model.fileInfo(proxyModel.mapToSource(ui->treeView->currentIndex()));

QMenucontextMenu;
if(!selected||fileOrFolder.isDir()){
QAction*openFolder=
contextMenu.addAction(tr("Openfolderwithfilemanager"));
QAction*addFolder=contextMenu.addAction(tr("Addfolder"));
QAction*addPassword=contextMenu.addAction(tr("Addpassword"));
QAction*users=contextMenu.addAction(tr("Users"));
connect(openFolder,&QAction::triggered,this,&MainWindow::openFolder);
connect(addFolder,&QAction::triggered,this,&MainWindow::addFolder);
connect(addPassword,&QAction::triggered,this,&MainWindow::addPassword);
connect(users,&QAction::triggered,this,&MainWindow::onUsers);
}elseif(fileOrFolder.isFile()){
QAction*edit=contextMenu.addAction(tr("Edit"));
connect(edit,&QAction::triggered,this,&MainWindow::onEdit);
}
if(selected){
contextMenu.addSeparator();
if(fileOrFolder.isDir()){
QAction*renameFolder=contextMenu.addAction(tr("Renamefolder"));
connect(renameFolder,&QAction::triggered,this,
&MainWindow::renameFolder);
}elseif(fileOrFolder.isFile()){
QAction*renamePassword=contextMenu.addAction(tr("Renamepassword"));
connect(renamePassword,&QAction::triggered,this,
&MainWindow::renamePassword);
}
QAction*deleteItem=contextMenu.addAction(tr("Delete"));
connect(deleteItem,&QAction::triggered,this,&MainWindow::onDelete);
if(fileOrFolder.isDir()){
QStringdirPath=QDir::cleanPath(
Util::getDir(ui->treeView->currentIndex(),false,model,proxyModel));
QAction*reencrypt=contextMenu.addAction(tr("Re-encrypt"));
connect(reencrypt,&QAction::triggered,this,
[this,dirPath](){reencryptPath(dirPath);});
}
}
contextMenu.exec(globalPos);
}

voidMainWindow::showBrowserContextMenu(constQPoint&pos){
QMenu*contextMenu=ui->textBrowser->createStandardContextMenu(pos);
QPointglobalPos=ui->textBrowser->viewport()->mapToGlobal(pos);

contextMenu->exec(globalPos);
deletecontextMenu;
}

voidMainWindow::openFolder(){
QStringdir=
Util::getDir(ui->treeView->currentIndex(),false,model,proxyModel);

QStringpath=QDir::toNativeSeparators(dir);
QDesktopServices::openUrl(QUrl::fromLocalFile(path));
}

voidMainWindow::addFolder(){
boolok;
QStringdir=
Util::getDir(ui->treeView->currentIndex(),false,model,proxyModel);
QStringnewdir=
QInputDialog::getText(this,tr("Newfile"),
tr("NewFolder:\n(Willbeplacedin%1)")
.arg(QtPassSettings::getPassStore()+
Util::getDir(ui->treeView->currentIndex(),
true,model,proxyModel)),
QLineEdit::Normal,"",&ok);
if(!ok||newdir.isEmpty()){
return;
}
newdir.prepend(dir);
if(!QDir().mkdir(newdir)){
QMessageBox::warning(this,tr("Error"),
tr("Failedtocreatefolder:%1").arg(newdir));
return;
}
if(QtPassSettings::isAddGPGId(true)){
QStringgpgIdFile=newdir+"/.gpg-id";
QFilegpgId(gpgIdFile);
if(!gpgId.open(QIODevice::WriteOnly)){
QMessageBox::warning(
this,tr("Error"),
tr("Failedtocreate.gpg-idfilein:%1").arg(newdir));
return;
}
QList<UserInfo>users=QtPassSettings::getPass()->listKeys("",true);
for(constUserInfo&user:users){
if(user.enabled){
gpgId.write((user.key_id+"\n").toUtf8());
}
}
gpgId.close();
}
}

voidMainWindow::renameFolder(){
boolok;
QStringsrcDir=QDir::cleanPath(
Util::getDir(ui->treeView->currentIndex(),false,model,proxyModel));
QStringsrcDirName=QDir(srcDir).dirName();
QStringnewName=
QInputDialog::getText(this,tr("Renamefile"),tr("RenameFolderTo:"),
QLineEdit::Normal,srcDirName,&ok);
if(!ok||newName.isEmpty()){
return;
}
QStringdestDir=srcDir;
destDir.replace(srcDir.lastIndexOf(srcDirName),srcDirName.length(),newName);
QtPassSettings::getPass()->Move(srcDir,destDir);
}

voidMainWindow::editPassword(constQString&file){
if(!file.isEmpty()){
if(QtPassSettings::isUseGit()&&QtPassSettings::isAutoPull()){
onUpdate(true);
}
setPassword(file,false);
}
}

voidMainWindow::renamePassword(){
boolok;
QStringfile=getFile(ui->treeView->currentIndex(),false);
QStringfilePath=QFileInfo(file).path();
QStringfileName=QFileInfo(file).fileName();
if(fileName.endsWith(".gpg",Qt::CaseInsensitive)){
fileName.chop(4);
}

QStringnewName=
QInputDialog::getText(this,tr("Renamefile"),tr("RenameFileTo:"),
QLineEdit::Normal,fileName,&ok);
if(!ok||newName.isEmpty()){
return;
}
QStringnewFile=QDir(filePath).filePath(newName);
QtPassSettings::getPass()->Move(file,newFile);
}

voidMainWindow::clearTemplateWidgets(){
while(ui->gridLayout->count()>0){
QLayoutItem*item=ui->gridLayout->takeAt(0);
deleteitem->widget();
deleteitem;
}
ui->verticalLayoutPassword->setSpacing(0);
}

voidMainWindow::copyPasswordFromTreeview(){
QFileInfofileOrFolder=
model.fileInfo(proxyModel.mapToSource(ui->treeView->currentIndex()));

if(fileOrFolder.isFile()){
QStringfile=getFile(ui->treeView->currentIndex(),true);
//Disconnectanypreviousconnectiontoavoidaccumulation
disconnect(QtPassSettings::getPass(),&Pass::finishedShow,this,
&MainWindow::passwordFromFileToClipboard);
connect(QtPassSettings::getPass(),&Pass::finishedShow,this,
&MainWindow::passwordFromFileToClipboard);
QtPassSettings::getPass()->Show(file);
}
}

voidMainWindow::passwordFromFileToClipboard(constQString&text){
QStringListtokens=text.split('\n');
m_qtPass->copyTextToClipboard(tokens[0]);
}

voidMainWindow::addToGridLayout(intposition,constQString&field,
constQString&value){
QStringtrimmedField=field.trimmed();
QStringtrimmedValue=value.trimmed();

constQStringbuttonStyle=
"border-style:none;background:transparent;padding:0;margin:0;"
"icon-size:16px;color:inherit;";

//CombinetheCopybuttonandthelineeditinonewidget
auto*frame=newQFrame();
QLayout*ly=newQHBoxLayout();
ly->setContentsMargins(5,2,2,2);
ly->setSpacing(0);
frame->setLayout(ly);
if(QtPassSettings::getClipBoardType()!=Enums::CLIPBOARD_NEVER){
auto*fieldLabel=newQPushButtonWithClipboard(trimmedValue,this);
connect(fieldLabel,&QPushButtonWithClipboard::clicked,m_qtPass,
&QtPass::copyTextToClipboard);

fieldLabel->setStyleSheet(buttonStyle);
frame->layout()->addWidget(fieldLabel);
}

if(QtPassSettings::isUseQrencode()){
auto*qrbutton=newQPushButtonAsQRCode(trimmedValue,this);
connect(qrbutton,&QPushButtonAsQRCode::clicked,m_qtPass,
&QtPass::showTextAsQRCode);
qrbutton->setStyleSheet(buttonStyle);
frame->layout()->addWidget(qrbutton);
}

//settheechomodetopassword,ifthefieldis"password"
constQStringlineStyle=
QtPassSettings::isUseMonospace()
?"border-style:none;background:transparent;font-family:"
"monospace;"
:"border-style:none;background:transparent;";

if(QtPassSettings::isHidePassword()&&trimmedField==tr("Password")){
auto*line=newQLineEdit();
line->setObjectName(trimmedField);
line->setText(trimmedValue);
line->setReadOnly(true);
line->setStyleSheet(lineStyle);
line->setContentsMargins(0,0,0,0);
line->setEchoMode(QLineEdit::Password);
auto*showButton=newQPushButtonShowPassword(line,this);
showButton->setStyleSheet(buttonStyle);
showButton->setContentsMargins(0,0,0,0);
frame->layout()->addWidget(showButton);
frame->layout()->addWidget(line);
}else{
auto*line=newQTextBrowser();
line->setOpenExternalLinks(true);
line->setOpenLinks(true);
line->setMaximumHeight(26);
line->setMinimumHeight(26);
line->setSizePolicy(
QSizePolicy(QSizePolicy::Expanding,QSizePolicy::Minimum));
line->setObjectName(trimmedField);
trimmedValue.replace(Util::protocolRegex(),R"(<ahref="\1">\1</a>)");
line->setText(trimmedValue);
line->setReadOnly(true);
line->setStyleSheet(lineStyle);
line->setContentsMargins(0,0,0,0);
frame->layout()->addWidget(line);
}

frame->setStyleSheet(
".QFrame{border:1pxsolidlightgrey;border-radius:5px;}");

//setintothelayout
ui->gridLayout->addWidget(newQLabel(trimmedField),position,0);
ui->gridLayout->addWidget(frame,position,1);
}

voidMainWindow::showStatusMessage(constQString&msg,inttimeout){
