voidMainWindow::reencryptPath(constQString&dir){
QDircheckDir(dir);
if(!checkDir.exists()){
QMessageBox::critical(this,tr("Error"),
tr("Directorydoesnotexist:%1").arg(dir));
return;
}

intret=QMessageBox::question(
this,tr("Re-encryptpasswords"),
tr("Re-encryptallpasswordsin%1?\n\n"
"Thiswillre-encryptALLpasswordfilesinthisfolder"
"usingthecurrentrecipientsdefinedin.gpg-id.\n\n"
"Thismayrewritemanyfilesandcannotbeundoneeasily.\n\n"
"Continue?")
.arg(QDir(dir).dirName()),
QMessageBox::Yes|QMessageBox::No);

if(ret!=QMessageBox::Yes)
return;

//Preventdoubleexecution-usesamemethodasstartReencryptPath
setUiElementsEnabled(false);
ui->treeView->setDisabled(true);

QtPassSettings::getImitatePass()->reencryptPath(
QDir::cleanPath(QDir(dir).absolutePath()));
}

voidMainWindow::startReencryptPath(){
setUiElementsEnabled(false);
ui->treeView->setDisabled(true);
}

voidMainWindow::endReencryptPath(){setUiElementsEnabled(true);}

